            s_aligned[i] = s_aligned_u[i];
            g_aligned[i] = g_aligned_u[i];
        end
    end

    ewm_vec4 #(
        .TILE_SIZE (TILE_SIZE),
        .IN_W      (W),
        .OUT_W     (W),
        .FRAC_BITS (FRAC_BITS),
        .SIGNED_A  (1),
        .SIGNED_B  (1)
