        .rst_n    (rst_n),
        .in_valid (join_valid),
        .in_ready (join_ready),
        .out_ready(y_ready),
        .out_valid(y_valid),
        .a_vec    (g_aligned),
        .b_vec    (s_aligned),
        .y_vec    (y_vec_u)
    );

    always_comb begin
        for (int i=0; i<TILE_SIZE; i++) begin
            y_vec[i] = $signed(y_vec_u[i]);
        end
    end

endmodule

