    assign xt_r_int      = join_b_ready;

    // ========== EW 更新 ==========
    logic [S_ADDR_W-1:0] s_addr_cnt;
    wire  [S_ADDR_W-1:0] s_addr_mux = s_addr_cnt;
    wire join_fire = join_out_valid && join_out_ready_int;
    always_ff @(posedge clk or negedge rst_n) begin
