    logic                         s_out_ready;
    logic signed [DATA_WIDTH-1:0] s_out_vec [TILE_SIZE-1:0];

    ew_update_vec4 #(
        .TILE_SIZE (TILE_SIZE),
        .W         (DATA_WIDTH),
        .S_ADDR_W  (S_ADDR_W)
    ) u_ew (
        .clk       (clk),
